    96→	if srv.RequestHandlers == nil {
    97→		srv.RequestHandlers = map[string]RequestHandler{}
    98→		for k, v := range DefaultRequestHandlers {
    99→			srv.RequestHandlers[k] = v
   100→		}
   101→	}
   102→	if srv.ChannelHandlers == nil {
