   104→		for k, v := range DefaultChannelHandlers {
   105→			srv.ChannelHandlers[k] = v
   106→		}
   107→	}
   108→	if srv.SubsystemHandlers == nil {
   109→		srv.SubsystemHandlers = map[string]SubsystemHandler{}
